    try:
        tree = ast.parse(script, mode="exec")
    except SyntaxError:
        return False

    visitor = _SafeVisitor()
    try:
        visitor.visit(tree)
        return True
    except UnsafeOperation:
        return False


def evaluate_safe_script(script: str):
    """
    Execute a script that has been validated to contain only safe operations.
    Returns:
        - The value of the last expression if the script ends with an expression.
        - None if there is no final expression.
        - A string error message if execution fails.
    """
    try:
        tree = ast.parse(script, mode="exec")
    except SyntaxError as e:
        return f"Error executing script: {e.__class__.__name__}: {e}"

    # Validate again defensively
    try:
        _SafeVisitor().visit(tree)
    except UnsafeOperation as e:
        return f"Error executing script: {e}"

    env = {"__builtins__": {}}
    try:
        if tree.body and isinstance(tree.body[-1], ast.Expr):
            # Execute all but the last expression
            prefix_body = tree.body[:-1]
            if prefix_body:
                try:
                    module_node = ast.Module(body=prefix_body, type_ignores=[])  # py3.8+
                except TypeError:
                    module_node = ast.Module(body=prefix_body)  # older versions
                ast.fix_missing_locations(module_node)
                code_prefix = compile(module_node, "<safe_script>", "exec")
                exec(code_prefix, env, env)

            # Evaluate the last expression to produce a result
            last_expr = tree.body[-1].value
            expr_node = ast.Expression(last_expr)
            ast.fix_missing_locations(expr_node)
            code_expr = compile(expr_node, "<safe_script>", "eval")
            return eval(code_expr, env, env)
        else:
            # No final expression; just execute
            code = compile(tree, "<safe_script>", "exec")
            exec(code, env, env)
            return None
    except Exception as e:
        return f"Error executing script: {e.__class__.__name__}: {e}"

