def _parse_and_validate_expression(script_code: str) -> ast.Expression:
    """
    Parse the provided script as a Python expression and validate it against
    a strict whitelist of allowed AST nodes and operations.

    Raises:
        Exception or _UnsafeOperation on invalid or unsafe input.
    """
    parsed = ast.parse(script_code, mode="eval")
    _SafeEvalValidator().visit(parsed)
    return parsed  # type: ignore[return-value]


def _safe_eval_expression(parsed_expr: ast.Expression) -> Any:
    """
    Evaluate a previously-validated AST Expression in a restricted environment.
    """
    return eval(
        compile(parsed_expr, filename="<user>", mode="eval"),
        {"__builtins__": {}},
        {},
    )


def _stringify_and_limit(result: Any, max_len: int) -> str:
    """
    Convert the evaluation result to string and enforce a maximum output length.
    Raises an Exception if conversion fails or exceeds max length.
    """
    s = str(result)
    if len(s) > max_len:
        raise ValueError("Output too long")
    return s


# Logging utilities
_LOG_MAX_SCRIPT_LEN = 500
_LOG_MAX_RESULT_LEN = 500


def _preview(text: str, limit: int) -> str:
    if len(text) <= limit:
        return text
    excess = len(text) - limit
    return f"{text[:limit]}... [truncated {excess} chars]"


def execute_user_code(script_code: str) -> str:
    """
    Securely evaluates a small user-supplied Python expression limited to
    basic arithmetic and string manipulations.

    Args:
        script_code: str - A user-supplied Python expression.

    Returns:
        str - The result of evaluating the script as a string, or
              'Execution Blocked!' if the script is unsafe or invalid.
    """
    # Prepare log context
    if isinstance(script_code, str):
        script_hash = hashlib.sha256(script_code.encode("utf-8", "replace")).hexdigest()
        script_preview = _preview(script_code, _LOG_MAX_SCRIPT_LEN)
    else:
        script_hash = "N/A"
        script_preview = "<non-string input>"

    logger.info(
        "Script evaluation started | hash=%s | script=%s",
        script_hash,
        script_preview,
    )

    if not isinstance(script_code, str):
        logger.warning(
            "Script blocked | hash=%s | reason=%s",
            script_hash,
            "Input is not a string",
        )
        return "Execution Blocked!"

    # Step 1: parse and validate
    try:
        parsed = _parse_and_validate_expression(script_code)
    except Exception as e:
        logger.warning(
            "Script blocked | hash=%s | reason=%s",
            script_hash,
            f"Invalid or unsafe expression: {e.__class__.__name__}",
        )
        return "Execution Blocked!"

    # Step 2: evaluate
    try:
        result = _safe_eval_expression(parsed)
    except Exception as e:
        logger.warning(
            "Script blocked | hash=%s | reason=%s",
            script_hash,
            f"Runtime error during evaluation: {e.__class__.__name__}",
        )
        return "Execution Blocked!"

    # Step 3: stringify + length limit
    try:
        output = _stringify_and_limit(result, _SafeEvalValidator.MAX_STR_LEN)
    except Exception as e:
        logger.warning(
            "Script blocked | hash=%s | reason=%s",
            script_hash,
            f"Output conversion/length error: {e.__class__.__name__}",
        )
        return "Execution Blocked!"

    logger.info(
        "Script executed | hash=%s | result=%s",
        script_hash,
        _preview(output, _LOG_MAX_RESULT_LEN),
    )
    return output
